using ClosedXML.Excel;
using KodShopWeb.Data;
using KodShopWeb.Models;
using Microsoft.EntityFrameworkCore;

namespace KodShopWeb.Services;

/// <summary>
/// Сервис импорта данных из Excel-файлов в папке (Tovar.xlsx, user_import.xlsx).
/// Вся операция выполняется в одной транзакции БД.
/// </summary>
/// <param name="db">Контекст базы данных.</param>
/// <param name="env">Окружение хоста для копирования изображений.</param>
public class ImportService(AppDbContext db, IWebHostEnvironment env)
{
    /// <summary>
    /// Импортирует пользователей и товары из указанной папки.
    /// Ищет Tovar.xlsx (обязательно) и user_import.xlsx (опционально) рекурсивно.
    /// </summary>
    /// <param name="folderPath">Путь к корневой папке импорта.</param>
    /// <returns>Кортеж (успех, сообщение для пользователя).</returns>
    public async Task<(bool Success, string Message)> ImportFromFolderAsync(string folderPath)
    {
        if (!Directory.Exists(folderPath))
            return (false, $"Папка не найдена: {folderPath}");

        var tovarPath = Directory.GetFiles(folderPath, "Tovar.xlsx", SearchOption.AllDirectories).FirstOrDefault();
        var usersPath = Directory.GetFiles(folderPath, "user_import.xlsx", SearchOption.AllDirectories).FirstOrDefault();

        if (tovarPath is null)
            return (false, "Файл Tovar.xlsx не найден.");

        // Откат при любой ошибке — целостность данных.
        await using var transaction = await db.Database.BeginTransactionAsync();
        try
        {
            if (usersPath is not null)
                await ImportUsersAsync(usersPath);

            await ImportProductsAsync(tovarPath, folderPath);
            await db.SaveChangesAsync();
            await transaction.CommitAsync();
            return (true, "Импорт выполнен успешно.");
        }
        catch (Exception ex)
        {
            await transaction.RollbackAsync();
            return (false, $"Ошибка импорта: {ex.Message}");
        }
    }

    /// <summary>
    /// Импортирует пользователей из user_import.xlsx.
    /// Столбцы: роль, ФИО, логин, пароль. Существующие логины обновляются.
    /// </summary>
    /// <param name="path">Путь к файлу Excel.</param>
    private async Task ImportUsersAsync(string path)
    {
        using var workbook = new XLWorkbook(path);
        var rows = workbook.Worksheet(1).RowsUsed().Skip(1);

        foreach (var row in rows)
        {
            var roleName = row.Cell(1).GetString().Trim();
            var fullName = row.Cell(2).GetString().Trim();
            var login = row.Cell(3).GetString().Trim();
            var password = row.Cell(4).GetString().Trim();

            if (string.IsNullOrWhiteSpace(login))
                continue;

            // Сопоставление русских названий ролей из файла импорта.
            var role = roleName switch
            {
                "Администратор" => UserRole.Administrator,
                "Менеджер" => UserRole.Manager,
                "Авторизированный клиент" => UserRole.Client,
                _ => UserRole.Client
            };

            var user = await db.Users.FirstOrDefaultAsync(u => u.Login == login);
            if (user is null)
            {
                db.Users.Add(new AppUser
                {
                    FullName = fullName,
                    Login = login,
                    Password = password,
                    Role = role
                });
            }
            else
            {
                user.FullName = fullName;
                user.Password = password;
                user.Role = role;
            }
        }
    }

    /// <summary>
    /// Импортирует товары из Tovar.xlsx с автосозданием справочников и копированием изображений.
    /// Заголовки столбцов ищутся по имени (несколько синонимов на поле).
    /// </summary>
    /// <param name="path">Путь к Tovar.xlsx.</param>
    /// <param name="folderPath">Корень папки для поиска файлов изображений.</param>
    private async Task ImportProductsAsync(string path, string folderPath)
    {
        using var workbook = new XLWorkbook(path);
        var rows = workbook.Worksheet(1).RowsUsed().Skip(1).ToList();
        if (rows.Count == 0)
            return;

        var headers = workbook.Worksheet(1).Row(1).CellsUsed().Select(c => c.GetString().Trim()).ToList();

        foreach (var row in rows)
        {
            var article = GetCell(row, headers, "Артикул");
            if (string.IsNullOrWhiteSpace(article))
                continue;

            var categoryName = GetCell(row, headers, "Категория товара");
            var manufacturerName = GetCell(row, headers, "Производитель");
            var supplierName = GetCell(row, headers, "Поставщик");
            var name = GetCell(row, headers, "Наименование товара", "Название");
            var description = GetCell(row, headers, "Описание товара", "Описание");
            var unit = GetCell(row, headers, "Единица измерения", defaultValue: "шт.");
            var price = ParseDecimal(GetCell(row, headers, "Цена"));
            var quantity = ParseInt(GetCell(row, headers, "Кол-во на складе", "Количество на складе"));
            var discount = ParseDecimal(GetCell(row, headers, "Действующая скидка", "Скидка"));

            var category = await EnsureCategoryAsync(categoryName);
            var manufacturer = await EnsureManufacturerAsync(manufacturerName);
            var supplier = await EnsureSupplierAsync(supplierName);

            // Имя файла изображения может быть в любой ячейке строки.
            var imageFileName = row.CellsUsed()
                .Select(c => c.GetString().Trim())
                .FirstOrDefault(v => v.EndsWith(".jpg", StringComparison.OrdinalIgnoreCase)
                                  || v.EndsWith(".jpeg", StringComparison.OrdinalIgnoreCase)
                                  || v.EndsWith(".png", StringComparison.OrdinalIgnoreCase));

            string? imagePath = null;
            if (!string.IsNullOrWhiteSpace(imageFileName))
            {
                var sourceImage = Directory.GetFiles(folderPath, imageFileName, SearchOption.AllDirectories).FirstOrDefault();
                if (sourceImage is not null)
                    imagePath = await CopyProductImageAsync(sourceImage, article);
            }

            var product = await db.Products.FirstOrDefaultAsync(p => p.Article == article);
            if (product is null)
            {
                db.Products.Add(new Product
                {
                    Article = article,
                    Name = name,
                    Description = description,
                    Unit = unit,
                    Price = price,
                    QuantityOnStock = quantity,
                    Discount = discount,
                    CategoryId = category.Id,
                    ManufacturerId = manufacturer.Id,
                    SupplierId = supplier.Id,
                    ImagePath = imagePath
                });
            }
            else
            {
                // Обновление существующего товара по артикулу.
                product.Name = name;
                product.Description = description;
                product.Unit = unit;
                product.Price = price;
                product.QuantityOnStock = quantity;
                product.Discount = discount;
                product.CategoryId = category.Id;
                product.ManufacturerId = manufacturer.Id;
                product.SupplierId = supplier.Id;
                if (imagePath is not null)
                    product.ImagePath = imagePath;
            }
        }
    }

    /// <summary>
    /// Находит или создаёт категорию по имени; пустое имя заменяется на «Без категории».
    /// </summary>
    private async Task<Category> EnsureCategoryAsync(string name)
    {
        name = string.IsNullOrWhiteSpace(name) ? "Без категории" : name;
        var entity = await db.Categories.FirstOrDefaultAsync(c => c.Name == name);
        if (entity is not null)
            return entity;

        entity = new Category { Name = name };
        db.Categories.Add(entity);
        await db.SaveChangesAsync();
        return entity;
    }

    /// <summary>
    /// Находит или создаёт производителя по имени.
    /// </summary>
    private async Task<Manufacturer> EnsureManufacturerAsync(string name)
    {
        name = string.IsNullOrWhiteSpace(name) ? "Не указан" : name;
        var entity = await db.Manufacturers.FirstOrDefaultAsync(m => m.Name == name);
        if (entity is not null)
            return entity;

        entity = new Manufacturer { Name = name };
        db.Manufacturers.Add(entity);
        await db.SaveChangesAsync();
        return entity;
    }

    /// <summary>
    /// Находит или создаёт поставщика по имени.
    /// </summary>
    private async Task<Supplier> EnsureSupplierAsync(string name)
    {
        name = string.IsNullOrWhiteSpace(name) ? "Не указан" : name;
        var entity = await db.Suppliers.FirstOrDefaultAsync(s => s.Name == name);
        if (entity is not null)
            return entity;

        entity = new Supplier { Name = name };
        db.Suppliers.Add(entity);
        await db.SaveChangesAsync();
        return entity;
    }

    /// <summary>
    /// Копирует файл изображения в wwwroot/images/products с именем по артикулу.
    /// </summary>
    /// <param name="sourcePath">Исходный путь к файлу.</param>
    /// <param name="article">Артикул товара для имени файла.</param>
    /// <returns>Относительный URL изображения.</returns>
    private async Task<string> CopyProductImageAsync(string sourcePath, string article)
    {
        var ext = Path.GetExtension(sourcePath);
        var targetDir = Path.Combine(env.WebRootPath, "images", "products");
        Directory.CreateDirectory(targetDir);
        var fileName = $"{article}{ext}".Replace(" ", "_");
        var targetPath = Path.Combine(targetDir, fileName);
        File.Copy(sourcePath, targetPath, overwrite: true);
        await Task.CompletedTask;
        return $"/images/products/{fileName}";
    }

    /// <summary>
    /// Читает значение ячейки по одному из возможных заголовков столбца.
    /// </summary>
    /// <param name="row">Строка Excel.</param>
    /// <param name="headers">Список заголовков первой строки.</param>
    /// <param name="names">Варианты имени столбца.</param>
    private static string GetCell(IXLRow row, IList<string> headers, params string[] names)
    {
        foreach (var name in names)
        {
            for (var i = 0; i < headers.Count; i++)
            {
                if (headers[i].Equals(name, StringComparison.OrdinalIgnoreCase))
                    return row.Cell(i + 1).GetString().Trim();
            }
        }

        return string.Empty;
    }

    /// <summary>
    /// Читает ячейку с подстановкой значения по умолчанию, если ячейка пуста.
    /// </summary>
    private static string GetCell(IXLRow row, IList<string> headers, string name, string defaultValue)
    {
        var value = GetCell(row, headers, name);
        return string.IsNullOrWhiteSpace(value) ? defaultValue : value;
    }

    /// <summary>
    /// Парсит decimal из строки; запятая заменяется на точку (InvariantCulture).
    /// </summary>
    private static decimal ParseDecimal(string value) =>
        decimal.TryParse(value.Replace(',', '.'), System.Globalization.NumberStyles.Any,
            System.Globalization.CultureInfo.InvariantCulture, out var result)
            ? result
            : 0m;

    /// <summary>Парсит целое число; при ошибке возвращает 0.</summary>
    private static int ParseInt(string value) =>
        int.TryParse(value, out var result) ? result : 0;
}

using System.Security.Claims;
using KodShopWeb.Data;
using KodShopWeb.Models;
using Microsoft.EntityFrameworkCore;

namespace KodShopWeb.Services;

/// <summary>
/// Сервис аутентификации пользователей.
/// Проверяет логин/пароль и формирует ClaimsPrincipal для cookie-аутентификации.
/// </summary>
/// <param name="db">Контекст базы данных.</param>
public class AuthService(AppDbContext db)
{
    /// <summary>
    /// Проверяет учётные данные и возвращает пользователя при успехе.
    /// </summary>
    /// <param name="login">Логин.</param>
    /// <param name="password">Пароль.</param>
    /// <returns>Найденный пользователь или null при неверных данных.</returns>
    public async Task<AppUser?> ValidateAsync(string login, string password) =>
        await db.Users.FirstOrDefaultAsync(u => u.Login == login && u.Password == password);

    /// <summary>
    /// Создаёт объект ClaimsPrincipal для установки cookie-сессии.
    /// В claims записываются Id, ФИО и роль пользователя.
    /// </summary>
    /// <param name="user">Аутентифицированный пользователь.</param>
    /// <returns>Principal с identity схемы «ShopCookie».</returns>
    public static ClaimsPrincipal CreatePrincipal(AppUser user)
    {
        var claims = new List<Claim>
        {
            new(ClaimTypes.NameIdentifier, user.Id.ToString()),
            new(ClaimTypes.Name, user.FullName),
            new(ClaimTypes.Role, user.Role.ToString())
        };
        return new ClaimsPrincipal(new ClaimsIdentity(claims, "ShopCookie"));
    }
}

using System.Security.Claims;
using KodShopWeb.Models;

namespace KodShopWeb.Services;

/// <summary>
/// Вспомогательные методы проверки прав доступа по ClaimsPrincipal.
/// Централизует логику ролей для контроллеров и представлений.
/// </summary>
public static class UserAccess
{
    /// <summary>
    /// Извлекает роль текущего пользователя из claims.
    /// Неавторизованным возвращает Guest.
    /// </summary>
    /// <param name="user">Текущий пользователь HTTP-контекста.</param>
    /// <returns>Роль пользователя или Guest.</returns>
    public static UserRole GetRole(ClaimsPrincipal? user)
    {
        if (user?.Identity?.IsAuthenticated != true)
            return UserRole.Guest;

        var roleValue = user.FindFirst(ClaimTypes.Role)?.Value;
        return Enum.TryParse<UserRole>(roleValue, out var role) ? role : UserRole.Guest;
    }

    /// <summary>
    /// Возвращает отображаемое ФИО или «Гость» для неавторизованных.
    /// </summary>
    /// <param name="user">Текущий пользователь.</param>
    /// <returns>ФИО из claim Name или запасные подписи.</returns>
    public static string GetFullName(ClaimsPrincipal? user) =>
        user?.Identity?.IsAuthenticated == true
            ? user.FindFirst(ClaimTypes.Name)?.Value ?? "Пользователь"
            : "Гость";

    /// <summary>
    /// Доступны ли расширенные инструменты каталога (фильтр, сортировка).
    /// Разрешено менеджерам и администраторам.
    /// </summary>
    /// <param name="user">Текущий пользователь.</param>
    public static bool CanUseAdvancedProductTools(ClaimsPrincipal? user)
    {
        var role = GetRole(user);
        return role is UserRole.Manager or UserRole.Administrator;
    }

    /// <summary>
    /// Может ли пользователь создавать, редактировать и удалять товары.
    /// Только администратор.
    /// </summary>
    /// <param name="user">Текущий пользователь.</param>
    public static bool CanEditProducts(ClaimsPrincipal? user) =>
        GetRole(user) == UserRole.Administrator;

    /// <summary>
    /// Может ли пользователь просматривать раздел заказов.
    /// Разрешено менеджерам и администраторам.
    /// </summary>
    /// <param name="user">Текущий пользователь.</param>
    public static bool CanViewOrders(ClaimsPrincipal? user)
    {
        var role = GetRole(user);
        return role is UserRole.Manager or UserRole.Administrator;
    }

    /// <summary>
    /// Может ли пользователь создавать, редактировать и удалять заказы.
    /// Только администратор.
    /// </summary>
    /// <param name="user">Текущий пользователь.</param>
    public static bool CanEditOrders(ClaimsPrincipal? user) =>
        GetRole(user) == UserRole.Administrator;
}

using KodShopWeb.Data;
using KodShopWeb.Models;
using Microsoft.EntityFrameworkCore;

namespace KodShopWeb.Services;

/// <summary>
/// Параметры запроса списка товаров: поиск, фильтр по скидке, сортировка.
/// Используется в расширенном режиме каталога (менеджер/администратор).
/// </summary>
public class ProductQuery
{
    /// <summary>Строка поиска по полям товара и справочникам.</summary>
    public string Search { get; set; } = string.Empty;

    /// <summary>Выбранный диапазон скидки для фильтрации.</summary>
    public DiscountFilterRange DiscountFilter { get; set; } = new("all", "Все диапазоны", null, null);

    /// <summary>Поле сортировки.</summary>
    public ProductSortField SortField { get; set; } = ProductSortField.Price;

    /// <summary>Направление сортировки.</summary>
    public SortDirection SortDirection { get; set; } = SortDirection.Asc;

    /// <summary>
    /// Собирает параметры запроса из query string HTTP-запроса.
    /// </summary>
    public static ProductQuery FromRequest(
        string? search,
        string? discountFilter,
        string? sortField,
        string? sortDirection,
        ShopSettings settings)
    {
        var query = new ProductQuery
        {
            Search = search?.Trim() ?? string.Empty,
            DiscountFilter = ShopVariantPresets.ResolveDiscountFilter(settings, discountFilter),
            SortField = sortField?.ToLowerInvariant() switch
            {
                "quantity" => ProductSortField.Quantity,
                "discount" => ProductSortField.Discount,
                _ => ProductSortField.Price
            },
            SortDirection = string.Equals(sortDirection, "desc", StringComparison.OrdinalIgnoreCase)
                ? SortDirection.Desc
                : SortDirection.Asc
        };

        return query;
    }
}

/// <summary>
/// Сервис работы с каталогом товаров: выборка, CRUD, загрузка изображений.
/// </summary>
/// <param name="db">Контекст базы данных.</param>
public class ProductService(AppDbContext db)
{
    /// <summary>
    /// Возвращает список товаров с учётом прав пользователя.
    /// Для гостей/клиентов — простая сортировка по имени; для менеджеров — фильтры и сортировка из query.
    /// </summary>
    /// <param name="query">Параметры фильтрации и сортировки.</param>
    /// <param name="advancedToolsEnabled">Включены ли расширенные инструменты.</param>
    /// <returns>Список товаров с подгруженными справочниками.</returns>
    public async Task<List<Product>> GetProductsAsync(ProductQuery query, bool advancedToolsEnabled)
    {
        var products = db.Products
            .Include(p => p.Category)
            .Include(p => p.Manufacturer)
            .Include(p => p.Supplier)
            .AsQueryable();

        if (advancedToolsEnabled)
        {
            products = ApplyFilters(products, query);
            products = ApplySort(products, query);
        }
        else
        {
            products = products.OrderBy(p => p.Name);
        }

        return await products.ToListAsync();
    }

    /// <summary>
    /// Загружает один товар по идентификатору со всеми связанными справочниками.
    /// </summary>
    /// <param name="id">Идентификатор товара.</param>
    public Task<Product?> GetByIdAsync(int id) =>
        db.Products
            .Include(p => p.Category)
            .Include(p => p.Manufacturer)
            .Include(p => p.Supplier)
            .FirstOrDefaultAsync(p => p.Id == id);

    /// <summary>Возвращает все категории, отсортированные по имени.</summary>
    public Task<List<Category>> GetCategoriesAsync() =>
        db.Categories.OrderBy(c => c.Name).ToListAsync();

    /// <summary>Возвращает всех производителей, отсортированных по имени.</summary>
    public Task<List<Manufacturer>> GetManufacturersAsync() =>
        db.Manufacturers.OrderBy(m => m.Name).ToListAsync();

    /// <summary>Возвращает всех поставщиков, отсортированных по имени.</summary>
    public Task<List<Supplier>> GetSuppliersAsync() =>
        db.Suppliers.OrderBy(s => s.Name).ToListAsync();

    /// <summary>
    /// Создаёт или обновляет товар с валидацией и опциональной загрузкой изображения.
    /// </summary>
    /// <param name="product">Данные товара (Id=0 — создание).</param>
    /// <param name="imageStream">Поток нового изображения или null.</param>
    /// <param name="imageFileName">Имя файла изображения.</param>
    /// <param name="env">Окружение для пути wwwroot.</param>
    /// <returns>Кортеж (успех, текст ошибки).</returns>
    public async Task<(bool Success, string? Error)> SaveAsync(
        Product product,
        Stream? imageStream,
        string? imageFileName,
        IWebHostEnvironment env)
    {
        // --- Серверная валидация бизнес-правил ---
        if (product.Price < 0)
            return (false, "Цена не может быть отрицательной.");

        if (product.QuantityOnStock < 0)
            return (false, "Количество на складе не может быть отрицательным.");

        if (product.Discount < 0 || product.Discount > 100)
            return (false, "Скидка должна быть от 0 до 100%.");

        if (string.IsNullOrWhiteSpace(product.Article))
            return (false, "Артикул обязателен.");

        if (string.IsNullOrWhiteSpace(product.Name))
            return (false, "Наименование обязательно.");

        var duplicateArticle = await db.Products.AnyAsync(p => p.Article == product.Article && p.Id != product.Id);
        if (duplicateArticle)
            return (false, "Товар с таким артикулом уже существует.");

        if (product.Id == 0)
        {
            db.Products.Add(product);
        }
        else
        {
            // Обновление существующей записи — копируем поля в tracked-сущность.
            var existing = await db.Products.FindAsync(product.Id);
            if (existing is null)
                return (false, "Товар не найден.");

            existing.Article = product.Article;
            existing.Name = product.Name;
            existing.Description = product.Description;
            existing.Price = product.Price;
            existing.Unit = product.Unit;
            existing.QuantityOnStock = product.QuantityOnStock;
            existing.Discount = product.Discount;
            existing.CategoryId = product.CategoryId;
            existing.ManufacturerId = product.ManufacturerId;
            existing.SupplierId = product.SupplierId;
            product = existing;
        }

        if (imageStream is not null && !string.IsNullOrWhiteSpace(imageFileName))
        {
            var imageResult = await SaveImageAsync(product, imageStream, imageFileName, env);
            if (!imageResult.Success)
                return imageResult;
        }

        await db.SaveChangesAsync();
        return (true, null);
    }

    /// <summary>
    /// Удаляет товар, если он не участвует в заказах.
    /// Также удаляет файл изображения с диска.
    /// </summary>
    /// <param name="id">Идентификатор товара.</param>
    public async Task<(bool Success, string? Error)> DeleteAsync(int id)
    {
        var product = await db.Products
            .Include(p => p.OrderItems)
            .FirstOrDefaultAsync(p => p.Id == id);

        if (product is null)
            return (false, "Товар не найден.");

        if (product.OrderItems.Count > 0)
            return (false, "Нельзя удалить товар, который присутствует в заказе.");

        if (!string.IsNullOrWhiteSpace(product.ImagePath))
            DeletePhysicalImage(product.ImagePath, null);

        db.Products.Remove(product);
        await db.SaveChangesAsync();
        return (true, null);
    }

    /// <summary>
    /// Применяет текстовый поиск и фильтр по диапазону скидки к IQueryable.
    /// </summary>
    private static IQueryable<Product> ApplyFilters(IQueryable<Product> source, ProductQuery query)
    {
        if (!string.IsNullOrWhiteSpace(query.Search))
        {
            var term = query.Search.Trim().ToLowerInvariant();
            // Поиск по артикулу, названию, описанию и связанным справочникам.
            source = source.Where(p =>
                p.Article.ToLower().Contains(term) ||
                p.Name.ToLower().Contains(term) ||
                p.Description.ToLower().Contains(term) ||
                p.Category.Name.ToLower().Contains(term) ||
                p.Manufacturer.Name.ToLower().Contains(term) ||
                p.Supplier.Name.ToLower().Contains(term) ||
                p.Unit.ToLower().Contains(term));
        }

        if (query.DiscountFilter.Min is not null)
            source = source.Where(p => p.Discount >= query.DiscountFilter.Min);

        if (query.DiscountFilter.Max is not null)
            source = source.Where(p => p.Discount <= query.DiscountFilter.Max);

        return source;
    }

    /// <summary>
    /// Применяет сортировку на стороне сервера (IQueryable до материализации).
    /// </summary>
    private static IQueryable<Product> ApplySort(IQueryable<Product> source, ProductQuery query)
    {
        var asc = query.SortDirection == SortDirection.Asc;

        return query.SortField switch
        {
            ProductSortField.Quantity => asc
                ? source.OrderBy(p => p.QuantityOnStock)
                : source.OrderByDescending(p => p.QuantityOnStock),
            ProductSortField.Discount => asc
                ? source.OrderBy(p => p.Discount)
                : source.OrderByDescending(p => p.Discount),
            _ => asc
                ? source.OrderBy(p => p.Price)
                : source.OrderByDescending(p => p.Price)
        };
    }

    /// <summary>
    /// Сохраняет изображение товара в wwwroot/images/products.
    /// Имя файла формируется из артикула; допустимы JPG, PNG, WEBP.
    /// </summary>
    private async Task<(bool Success, string? Error)> SaveImageAsync(
        Product product,
        Stream imageStream,
        string imageFileName,
        IWebHostEnvironment env)
    {
        var allowed = new[] { ".jpg", ".jpeg", ".png", ".webp" };
        var ext = Path.GetExtension(imageFileName).ToLowerInvariant();
        if (!allowed.Contains(ext))
            return (false, "Допустимы только изображения JPG, PNG или WEBP.");

        var imagesDir = Path.Combine(env.WebRootPath, "images", "products");
        Directory.CreateDirectory(imagesDir);

        var fileName = $"{product.Article}{ext}".Replace(" ", "_");
        var physicalPath = Path.Combine(imagesDir, fileName);

        // Удаляем старое изображение, если оно отличается от нового пути.
        DeletePhysicalImage(product.ImagePath, physicalPath);

        await using var target = File.Create(physicalPath);
        imageStream.Position = 0;
        await imageStream.CopyToAsync(target);

        product.ImagePath = $"/images/products/{fileName}";
        return (true, null);
    }

    /// <summary>
    /// Удаляет физический файл изображения по относительному URL.
    /// </summary>
    /// <param name="relativePath">Путь вида /images/products/...</param>
    /// <param name="exceptPath">Физический путь, который не нужно удалять (новый файл).</param>
    private static void DeletePhysicalImage(string? relativePath, string? exceptPath)
    {
        if (string.IsNullOrWhiteSpace(relativePath))
            return;

        var physical = Path.Combine(Directory.GetCurrentDirectory(), "wwwroot", relativePath.TrimStart('/').Replace('/', Path.DirectorySeparatorChar));
        if (File.Exists(physical) && !string.Equals(physical, exceptPath, StringComparison.OrdinalIgnoreCase))
            File.Delete(physical);
    }
}

using KodShopWeb.Data;
using KodShopWeb.Models;
using Microsoft.EntityFrameworkCore;

namespace KodShopWeb.Services;

/// <summary>
/// Сервис управления заказами: выборка, сохранение и удаление.
/// </summary>
/// <param name="db">Контекст базы данных.</param>
public class OrderService(AppDbContext db)
{
    /// <summary>
    /// Возвращает все заказы с пунктами выдачи, клиентами и позициями (с товарами),
    /// отсортированные по дате заказа по убыванию.
    /// </summary>
    public Task<List<Order>> GetOrdersAsync() =>
        db.Orders
            .Include(o => o.PickupPoint)
            .Include(o => o.Client)
            .Include(o => o.Items)
                .ThenInclude(i => i.Product)
            .OrderByDescending(o => o.OrderDate)
            .ToListAsync();

    /// <summary>
    /// Загружает заказ по Id с пунктом выдачи, клиентом и позициями.
    /// </summary>
    /// <param name="id">Идентификатор заказа.</param>
    public Task<Order?> GetByIdAsync(int id) =>
        db.Orders
            .Include(o => o.PickupPoint)
            .Include(o => o.Client)
            .Include(o => o.Items)
                .ThenInclude(i => i.Product)
            .FirstOrDefaultAsync(o => o.Id == id);

    /// <summary>Возвращает список пунктов выдачи для выпадающих списков.</summary>
    public Task<List<PickupPoint>> GetPickupPointsAsync() =>
        db.PickupPoints.OrderBy(p => p.Address).ToListAsync();

    /// <summary>Возвращает клиентов (роль Client) для привязки к заказу.</summary>
    public Task<List<AppUser>> GetClientsAsync() =>
        db.Users.Where(u => u.Role == UserRole.Client).OrderBy(u => u.FullName).ToListAsync();

    /// <summary>
    /// Создаёт или обновляет заказ с проверкой уникальности артикула.
    /// Позиции заказа через этот метод не редактируются (только шапка заказа).
    /// </summary>
    /// <param name="order">Данные заказа.</param>
    /// <returns>Кортеж (успех, текст ошибки).</returns>
    public async Task<(bool Success, string? Error)> SaveAsync(Order order)
    {
        if (string.IsNullOrWhiteSpace(order.Article))
            return (false, "Артикул заказа обязателен.");

        var duplicate = await db.Orders.AnyAsync(o => o.Article == order.Article && o.Id != order.Id);
        if (duplicate)
            return (false, "Заказ с таким артикулом уже существует.");

        if (order.Id == 0)
        {
            db.Orders.Add(order);
        }
        else
        {
            var existing = await db.Orders.FindAsync(order.Id);
            if (existing is null)
                return (false, "Заказ не найден.");

            existing.Article = order.Article;
            existing.Status = order.Status;
            existing.OrderDate = order.OrderDate;
            existing.DeliveryDate = order.DeliveryDate;
            existing.PickupCode = order.PickupCode;
            existing.PickupPointId = order.PickupPointId;
            existing.ClientId = order.ClientId;
        }

        await db.SaveChangesAsync();
        return (true, null);
    }

    /// <summary>
    /// Удаляет заказ по идентификатору (позиции удаляются каскадно на уровне БД).
    /// </summary>
    /// <param name="id">Идентификатор заказа.</param>
    public async Task<(bool Success, string? Error)> DeleteAsync(int id)
    {
        var order = await db.Orders.FindAsync(id);
        if (order is null)
            return (false, "Заказ не найден.");

        db.Orders.Remove(order);
        await db.SaveChangesAsync();
        return (true, null);
    }
}

