    string SortFieldValue(ProductSortField field) => field switch
    {
        ProductSortField.Quantity => "quantity",
        ProductSortField.Discount => "discount",
        _ => "price"
    };
    var currentSortField = SortFieldValue(Model.SortField);
    var currentSortDirection = Model.SortDirection == SortDirection.Desc ? "desc" : "asc";
}

<section class="page-header">
    <h2>Список товаров</h2>
