        <input id="searchInput" name="search" class="form-control" placeholder="Поиск..." value="@Model.Search" />
        <select id="discountFilter" name="discountFilter" class="form-control">
            @foreach (var range in Model.DiscountFilterOptions)
            {
                if (range.Key == Model.DiscountFilterKey)
                {
                    <option value="@range.Key" selected="selected">@range.Label</option>
                }
                else
                {
                    <option value="@range.Key">@range.Label</option>
                }
            }
        </select>
        <select id="sortField" name="sortField" class="form-control">
            @if (Model.IsProfileVariant)
            {
                <option value="price" selected="@(currentSortField == "price" ? "selected" : null)">Цена</option>
                <option value="quantity" selected="@(currentSortField == "quantity" ? "selected" : null)">Количество на складе</option>
            }
