/* Панель поиска/фильтрации на странице товаров (4 колонки) */
.toolbar { display: grid; grid-template-columns: 2fr 1fr 1fr 1fr; gap: 0.75rem; margin-bottom: 1rem; }

/* --- Формы и элементы ввода --- */
.form-group { display: flex; flex-direction: column; gap: 0.35rem; margin-bottom: 0.85rem; }
.form-control { padding: 0.55rem 0.75rem; border: 1px solid #cbd5e1; border-radius: 8px; font: inherit; }

/* --- Кнопки --- */
.btn { border: none; border-radius: 8px; padding: 0.55rem 1rem; cursor: pointer; font: inherit; }
a.btn { display: inline-block; text-decoration: none; text-align: center; }
.btn-accent { background: var(--shop-accent, #546f94); color: #fff; }
.btn-secondary { background: #e2e8f0; color: #1f2937; }
.btn-danger { background: #dc2626; color: #fff; }
.btn-small { padding: 0.25rem 0.5rem; font-size: 0.85rem; }
.inline-form { display: inline; }
.field-error { color: #dc2626; font-size: 0.85rem; }

/* --- Таблица товаров / заказов --- */
.product-table-wrapper {
    overflow: auto; background: #fff; border-radius: 12px;
    box-shadow: 0 8px 24px rgba(15, 23, 42, 0.08);
}

.product-table { width: 100%; border-collapse: collapse; }
.product-table th, .product-table td { padding: 0.75rem; border-bottom: 1px solid #e5e7eb; vertical-align: top; }
.product-table th { background: #f8fafc; text-align: left; }
.product-thumb { width: 80px; height: 60px; object-fit: cover; border-radius: 6px; background: #f1f5f9; }
.product-preview { margin-top: 0.5rem; width: 300px; height: 200px; object-fit: cover; border-radius: 8px; border: 1px solid #cbd5e1; }
.description-cell { max-width: 260px; }

/* Отображение цены со скидкой: зачёркнутая старая и жирная новая */
