/**
 * Серверная фильтрация каталога: при изменении параметров отправляется GET-форма на Products/Index.
 * Параметры поиска и сортировки сохраняются в URL и восстанавливаются при перезагрузке страницы.
 */
(function () {
    const form = document.getElementById('productsFilterForm');
    if (!form) return;

    const searchInput = document.getElementById('searchInput');
    const discountFilter = document.getElementById('discountFilter');
    const sortField = document.getElementById('sortField');
    const sortDirection = document.getElementById('sortDirection');

    let debounceTimer;

    function submitForm() {
        if (typeof form.requestSubmit === 'function') {
            form.requestSubmit();
        } else {
            form.submit();
        }
    }

    function debouncedSubmit() {
        clearTimeout(debounceTimer);
        debounceTimer = setTimeout(submitForm, 350);
    }

    if (searchInput) {
        searchInput.addEventListener('input', debouncedSubmit);
    }

    [discountFilter, sortField, sortDirection].forEach(el => {
        if (el) el.addEventListener('change', submitForm);
    });
})();

namespace KodShopWeb.Models;

/// <summary>
/// Пользователь системы (клиент, менеджер или администратор).
/// Хранит учётные данные и связь с заказами клиента.
/// </summary>
public class AppUser
{
    /// <summary>Уникальный идентификатор пользователя.</summary>
    public int Id { get; set; }

    /// <summary>ФИО для отображения в интерфейсе.</summary>
    public string FullName { get; set; } = string.Empty;

    /// <summary>Логин для входа (уникальный).</summary>
    public string Login { get; set; } = string.Empty;

    /// <summary>Пароль (в учебном проекте хранится в открытом виде).</summary>
    public string Password { get; set; } = string.Empty;

    /// <summary>Роль определяет права доступа.</summary>
    public UserRole Role { get; set; }

    /// <summary>Электронная почта (необязательное поле).</summary>
    public string? Email { get; set; }

